// Parse Ollama response and extract JSON
const response = $input.first().json;
let scriptData;

try {
  // Ollama wraps response in a 'response' field
  const rawText = response.response || JSON.stringify(response);

  // Extract JSON from response
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    scriptData = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON found in response');
  }
} catch (error) {
  // Fallback script if parsing fails
  scriptData = {
    hook: "Want to catch more fish?",
    script: "Here's a pro tip that experienced anglers swear by. Pay attention to water temperature. Fish are cold-blooded, so their activity changes with temperature. In warmer water, fish metabolism speeds up and they feed more actively. In colder water, they slow down. Use a thermometer to check the water temp, then adjust your presentation speed accordingly. Fast retrieves in warm water, slow in cold. This simple adjustment can double your catch rate. Try it on your next fishing trip and see the difference!",
    cta: "Subscribe for more fishing tips!",
    tags: ["fishing", "fishingtips", "shorts"]
  };
}

return {
  json: scriptData
};

// Convert base64 audio to binary
const base64Audio = $input.first().json.stdout.trim();

return {
  json: $input.first().json,
  binary: {
    audio: {
      data: base64Audio,
      mimeType: 'audio/wav',
      fileName: 'narration.wav',
      fileExtension: 'wav'
    }
  }
};

const fs = require('fs');
const path = require('path');

// Configuration
const ORGANIZED_FOOTAGE_DIR = '/home/poe/organized-footage';
const CLIPS_NEEDED = 4;
const TARGET_DURATION = 60;

// Get script data
const scriptData = $input.first().json;
const scriptText = scriptData.script.toLowerCase();

// Smart category selection based on script content
const categoryWeights = {
  'catch': 0,
  'casting': 0,
  'reeling': 0,
  'action': 0,
  'scenery': 0,
  'underwater': 0,
  'gear': 0,
  'boat': 0,
  'broll': 0
};

// Analyze script to determine relevant categories
if (scriptText.includes('cast') || scriptText.includes('presentation')) categoryWeights.casting += 3;
if (scriptText.includes('fight') || scriptText.includes('reel')) categoryWeights.reeling += 3;
if (scriptText.includes('catch') || scriptText.includes('fish')) categoryWeights.catch += 2;
if (scriptText.includes('water') || scriptText.includes('lake') || scriptText.includes('river')) categoryWeights.scenery += 2;
if (scriptText.includes('gear') || scriptText.includes('lure') || scriptText.includes('bait')) categoryWeights.gear += 2;
if (scriptText.includes('under') || scriptText.includes('below')) categoryWeights.underwater += 2;

// Get clips from weighted categories
const selectedClips = [];
const sortedCategories = Object.entries(categoryWeights)
  .sort(([,a], [,b]) => b - a)
  .map(([cat]) => cat);

// Try to get clips from each category
for (const category of sortedCategories) {
  const categoryPath = path.join(ORGANIZED_FOOTAGE_DIR, category);

  if (fs.existsSync(categoryPath)) {
    const files = fs.readdirSync(categoryPath)
      .filter(f => /\.(mp4|mov|avi|mkv)$/i.test(f))
      .map(f => path.join(categoryPath, f));

    // Randomly select from this category
    if (files.length > 0) {
      const randomIndex = Math.floor(Math.random() * files.length);
      selectedClips.push(files[randomIndex]);
    }
  }

  if (selectedClips.length >= CLIPS_NEEDED) break;
}

// Fallback to b-roll if not enough clips
if (selectedClips.length < CLIPS_NEEDED) {
  const brollPath = path.join(ORGANIZED_FOOTAGE_DIR, 'broll');
  if (fs.existsSync(brollPath)) {
    const brollFiles = fs.readdirSync(brollPath)
      .filter(f => /\.(mp4|mov|avi|mkv)$/i.test(f))
      .map(f => path.join(brollPath, f));

    while (selectedClips.length < CLIPS_NEEDED && brollFiles.length > 0) {
      const randomIndex = Math.floor(Math.random() * brollFiles.length);
      selectedClips.push(brollFiles.splice(randomIndex, 1)[0]);
    }
  }
}

if (selectedClips.length === 0) {
  throw new Error('No video clips found in organized footage');
}

return {
  json: {
    ...scriptData,
    selectedClips: selectedClips,
    clipDuration: TARGET_DURATION / selectedClips.length,
    categoriesUsed: sortedCategories.slice(0, selectedClips.length)
  }
};

